func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	kBest := 5
	for jj := 0; jj < len(oris); jj++ {
		bestDelta := 1e18
		bestIdx := -1
		candidates := make([]struct{ idx int; delta float64 }, 0, kBest)
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			oldCost := dispatch.Assigns[ii].Cost
			ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				delta := newCost - oldCost
				if delta >= 0 && delta < 1e17 {
					candidates = append(candidates, struct{ idx int; delta float64 }{ii, delta})
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				} else {
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}
		sort.Slice(candidates, func(a, b int) bool { return candidates[a].delta < candidates[b].delta })
		if len(candidates) > 0 {
			topK := kBest
			if len(candidates) < topK {
				topK = len(candidates)
			}
			if topK == 1 {
				bestIdx = candidates[0].idx
				bestDelta = candidates[0].delta
			} else {
				regretSum := 0.0
				for t := 0; t < topK; t++ {
					if t == 0 {
						bestIdx = candidates[t].idx
						bestDelta = candidates[t].delta
					}
					if t == 1 {
						regretSum += candidates[t].delta - bestDelta
					}
				}
				score := bestDelta + regretSum*0.3
				for t := 0; t < topK; t++ {
					curRegret := 0.0
					if t == 0 && topK > 1 {
						curRegret = candidates[1].delta - candidates[t].delta
					} else if t > 0 && topK > 1 {
						curRegret = candidates[0].delta - candidates[t].delta
					}
					curScore := candidates[t].delta + curRegret*0.3
					if curScore < score || (curScore == score && candidates[t].delta < bestDelta) {
						score = curScore
						bestIdx = candidates[t].idx
						bestDelta = candidates[t].delta
					}
				}
			}
		}
		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestIdx].GenRoute()
		} else {
			fallbackOk := false
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				ok := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
				if ok {
					dispatch.Assigns[ii].GenRoute()
					fallbackOk = true
					break
				}
			}
			if !fallbackOk {
				if dispatch.AssignsLen < MAXASSIGNS {
					idx := dispatch.AssignsLen
					dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj])
					dispatch.Assigns[idx].GenRoute()
					dispatch.AssignsLen++
				} else {
					minLoad := int(^uint(0) >> 1)
					sel := -1
					for ii := 0; ii < dispatch.AssignsLen; ii++ {
						load := 0
						assign := &dispatch.Assigns[ii]
						for s := 0; s < assign.StationsLen; s++ {
							if assign.Stations[s].ReqCode > 0 {
								load++
							}
						}
						if load < minLoad {
							minLoad = load
							sel = ii
						}
					}
					if sel >= 0 {
						ok2 := dispatch.Assigns[sel].AddShip(total_ship+jj, oris[jj], dess[jj])
						if ok2 {
							dispatch.Assigns[sel].GenRoute()
						} else {
							for ii := 0; ii < dispatch.AssignsLen; ii++ {
								ok3 := dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj])
								if ok3 {
									dispatch.Assigns[ii].GenRoute()
									break
								}
							}
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	seedAssignIdx := dispatch.AssignsLen
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		shipId := total_ship + orderIdx
		ori := oris[orderIdx]
		des := dess[orderIdx]
		bestAssignIdx := -1
		bestDeltaCost := 1e308
		inserted := false
		for aIdx := 0; aIdx < dispatch.AssignsLen; aIdx++ {
			assign := &dispatch.Assigns[aIdx]
			origCost := assign.Cost
			trialOk := assign.AddShip(shipId, ori, des)
			if trialOk {
				assign.GenRoute()
				newCost := assign.Cost
				deltaCost := newCost - origCost
				if deltaCost < bestDeltaCost {
					bestDeltaCost = deltaCost
					bestAssignIdx = aIdx
				}
				assign.RemoveShip(shipId)
				assign.GenRoute()
			}
		}
		if bestAssignIdx != -1 && bestDeltaCost < 1e307 {
			finalAssign := &dispatch.Assigns[bestAssignIdx]
			ok := finalAssign.AddShip(shipId, ori, des)
			if ok {
				finalAssign.GenRoute()
				inserted = true
			}
		}
		if !inserted {
			if dispatch.AssignsLen < MAXASSIGNS {
				nextIdx := dispatch.AssignsLen
				ok := dispatch.Assigns[nextIdx].AddShip(shipId, ori, des)
				if ok {
					dispatch.Assigns[nextIdx].GenRoute()
					dispatch.AssignsLen++
					inserted = true
				} else if nextIdx > seedAssignIdx && seedAssignIdx < MAXASSIGNS {
					okSeed := dispatch.Assigns[seedAssignIdx].AddShip(shipId, ori, des)
					if okSeed {
						dispatch.Assigns[seedAssignIdx].GenRoute()
						inserted = true
					}
				}
			}
		}
		if !inserted && seedAssignIdx < MAXASSIGNS && dispatch.AssignsLen < MAXASSIGNS {
			ok := dispatch.Assigns[dispatch.AssignsLen].AddShip(shipId, ori, des)
			if ok {
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				dispatch.AssignsLen++
				seedAssignIdx = dispatch.AssignsLen - 1
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		slackWeight    = 0.6
		costWeight     = 0.4
		normalizeBase  = 50000.0
		improveFactor  = 1.08
		minSlackThresh = 3600
	)
	for jj := range oris {
		ori, des := oris[jj], dess[jj]
		shipID := total_ship + jj
		bestScore := 1e300
		bestIdx := -1
		var bestDelta float64
		var feasibleFound bool
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			prevCost := dispatch.Assigns[ii].Cost
			if prevCost < 0 {
				continue
			}
			ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			dispatch.Assigns[ii].GenRoute()
			newCost := dispatch.Assigns[ii].Cost
			if newCost < 0 {
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
				continue
			}
			feasibleFound = true
			delta := newCost - prevCost
			normDelta := delta / normalizeBase
			timeSlack := float64(des.TimeEnd - des.TimeStart)
			if timeSlack < minSlackThresh {
				timeSlack = minSlackThresh
			}
			score := costWeight*normDelta + slackWeight*(normalizeBase/timeSlack)
			if score < bestScore {
				bestScore = score
				bestIdx = ii
				bestDelta = delta
			}
			dispatch.Assigns[ii].RemoveShip(shipID)
			dispatch.Assigns[ii].GenRoute()
		}
		if !feasibleFound && bestIdx < 0 {
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				prevCost := dispatch.Assigns[ii].Cost
				if prevCost < 0 {
					continue
				}
				ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[ii].GenRoute()
					newCost := dispatch.Assigns[ii].Cost
					if newCost >= 0 {
						bestIdx = ii
						bestDelta = newCost - prevCost
						dispatch.Assigns[ii].RemoveShip(shipID)
						dispatch.Assigns[ii].GenRoute()
						break
					}
					dispatch.Assigns[ii].RemoveShip(shipID)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}
		selectedIdx := bestIdx
		if selectedIdx >= 0 && feasibleFound {
			for ii := 0; ii < dispatch.AssignsLen; ii++ {
				if ii == bestIdx {
					continue
				}
				prevCost := dispatch.Assigns[ii].Cost
				if prevCost < 0 {
					continue
				}
				ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
				if !ok {
					continue
				}
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost < 0 {
					dispatch.Assigns[ii].RemoveShip(shipID)
					dispatch.Assigns[ii].GenRoute()
					continue
				}
				delta := newCost - prevCost
				if delta < bestDelta*improveFactor {
					selectedIdx = ii
					bestDelta = delta
				}
				dispatch.Assigns[ii].RemoveShip(shipID)
				dispatch.Assigns[ii].GenRoute()
				if selectedIdx != bestIdx {
					break
				}
			}
		}
		if selectedIdx < 0 {
			seedIdx := dispatch.AssignsLen
			if seedIdx < MAXASSIGNS {
				ok := dispatch.Assigns[seedIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[seedIdx].GenRoute()
					if dispatch.Assigns[seedIdx].Cost >= 0 {
						dispatch.AssignsLen++
						selectedIdx = seedIdx
					} else {
						dispatch.Assigns[seedIdx].RemoveShip(shipID)
						dispatch.Assigns[seedIdx].GenRoute()
					}
				}
			}
		}
		if selectedIdx < 0 {
			for ii := 0; ii < MAXASSIGNS; ii++ {
				ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						if ii >= dispatch.AssignsLen {
							dispatch.AssignsLen = ii + 1
						}
						selectedIdx = ii
						break
					}
					dispatch.Assigns[ii].RemoveShip(shipID)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}
		if selectedIdx >= 0 {
			dispatch.Assigns[selectedIdx].AddShip(shipID, ori, des)
			dispatch.Assigns[selectedIdx].GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}

